// RAG系统核心流程示例
async function generateRAGResponse(query) {
  // 1. 生成查询向量
  const queryEmbedding = await embedQuery(query);

  // 2. 向量检索相关文档
  const relevantDocs = await vectorDB.similaritySearch(queryEmbedding, 5);

  // 3. 重排序提升相关性
  const rerankedDocs = await reranker.rerank(query, relevantDocs);

  // 4. 构建上下文
  const context = buildContext(rerankedDocs.slice(0, 3));

  // 5. 生成回复
  return await llm.complete({
    prompt: `基于以下信息回答问题：\n\n${context}\n\n问题：${query}\n回答：`
  });
}

